"""
TDD Stage: full_affine
Add beta (shift) addition to normalization with gamma: read beta RM, tilize beta, apply add<ROW> broadcast
"""

import pytest
import torch
import torch.nn.functional as F
import ttnn

from .layer_norm_rm import layer_norm_rm


def pytorch_reference(x_torch, gamma_torch, beta_torch):
    """PyTorch reference for this stage."""
    golden = F.layer_norm(
        x_torch, [x_torch.shape[-1]], weight=gamma_torch.squeeze(), bias=beta_torch.squeeze(), eps=1e-5
    )
    return golden


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 32, 128), id="1x1x32x128"),
        pytest.param((1, 1, 64, 128), id="1x1x64x128"),
        pytest.param((1, 1, 32, 256), id="1x1x32x256"),
        pytest.param((4, 2, 64, 64), id="4x2x64x64"),
    ],
)
def test_full_affine(device, shape):
    """Verify normalization with gamma scaling and beta shift."""
    layout = ttnn.ROW_MAJOR_LAYOUT
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)
    gamma_torch = torch.randn(1, 1, 1, shape[-1])
    beta_torch = torch.randn(1, 1, 1, shape[-1])

    expected = pytorch_reference(torch_input, gamma_torch, beta_torch)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=layout,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    gamma_ttnn = ttnn.from_torch(
        gamma_torch,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    beta_ttnn = ttnn.from_torch(
        beta_torch,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )

    ttnn_output = layer_norm_rm(ttnn_input, gamma=gamma_ttnn, beta=beta_ttnn)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.2,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
